// ServerList component for displaying servers
type ServerList struct {
	width  int
	height int
	model   *models.Model
}

// NewServerList creates a new server list component
func NewServerList(width, height int, model *models.Model) tea.Model {
	return &ServerList{
		width:  width,
		height: height,
		model:  model,
	}
}

// Init initializes the component
func (s *ServerList) Init() tea.Cmd {
	return s.model.Init()
}

// Update updates the component with new data
func (s *ServerList) Update(msg tea.Msg) tea.Cmd {
	// Update model with new servers
	s.model.Update(msg)
}

