// Helper functions
func getStatusIndicator(status server.ServerStatus) string {
	switch status {
	case server.StatusOnline:
		return "🟢"
	case server.StatusOffline:
		return "🔴"
	case server.StatusMaintenance:
		return "🟡"
	case server.StatusError:
		return "❌"
	default:
		return "⚪"
	}
}